import{_ as r,o as t,c as i,ag as n}from"./chunks/framework.5wcOFaQl.js";const u=JSON.parse('{"title":"Hermes Agent Compendium 🧠","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),a={name:"index.md"};function s(d,e,l,o,h,m){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="hermes-agent-compendium-🧠" tabindex="-1">Hermes Agent Compendium 🧠 <a class="header-anchor" href="#hermes-agent-compendium-🧠" aria-label="Permalink to &quot;Hermes Agent Compendium 🧠&quot;">​</a></h1><p>Dein deutscher Guide zu <strong>Hermes Agent</strong> – dem Open-Source KI-Agenten von Nous Research.</p><p>Hermes Agent ist ein autonomes KI-Framework, das in deinem Terminal, auf Messaging-Plattformen und in deiner IDE läuft. Es gehört zur selben Kategorie wie Claude Code, Codex und OpenClaw – aber mit einzigartigen Features wie selbstlernenden Skills und persistentem Gedächtnis.</p><hr><h2 id="🔥-highlights" tabindex="-1">🔥 Highlights <a class="header-anchor" href="#🔥-highlights" aria-label="Permalink to &quot;🔥 Highlights&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="flex:1;min-width:200px;padding:1.5rem;border:1px solid var(--vp-c-divider);border-radius:8px;background:var(--vp-c-bg-soft);"><h3>🧠 Skills</h3><p>Hermes lernt aus Erfahrung. Komplexe Workflows werden als Skills gespeichert und bei Bedarf geladen.</p><a href="/hermes-compendium/skills">Zu den Skills →</a></div><div style="flex:1;min-width:200px;padding:1.5rem;border:1px solid var(--vp-c-divider);border-radius:8px;background:var(--vp-c-bg-soft);"><h3>💾 Memory</h3><p>Persistentes Gedächtnis über Sitzungen hinweg – Hermes merkt sich deine Vorlieben und Projekte.</p><a href="/hermes-compendium/konfiguration">Konfiguration →</a></div><div style="flex:1;min-width:200px;border:1px solid var(--vp-c-divider);border-radius:8px;background:var(--vp-c-bg-soft);"></div></div><hr><h2 id="🎯-was-hermes-besonders-macht" tabindex="-1">🎯 Was Hermes besonders macht <a class="header-anchor" href="#🎯-was-hermes-besonders-macht" aria-label="Permalink to &quot;🎯 Was Hermes besonders macht&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Self-Improving Skills</strong></td><td>Hermes speichert erfolgreiche Workflows als wiederverwendbare Skills</td></tr><tr><td><strong>Multi-Platform Gateway</strong></td><td>Telegram, Discord, WhatsApp, Signal, Email &amp; 10+ Plattformen</td></tr><tr><td><strong>Provider-Agnostic</strong></td><td>Wechsel zwischen 20+ LLM-Providern (OpenRouter, Anthropic, DeepSeek, lokal)</td></tr><tr><td><strong>Cron-Jobs</strong></td><td>Geplante Aufgaben – Hermes arbeitet auch, wenn du schläfst</td></tr><tr><td><strong>Sub-Agenten</strong></td><td>Parallelaufgaben durch delegierte Kinder-Agenten</td></tr><tr><td><strong>Open Source</strong></td><td>Vollständig quelloffen (MIT-Lizenz) auf GitHub</td></tr></tbody></table><hr><h2 id="🚧-in-arbeit" tabindex="-1">🚧 In Arbeit <a class="header-anchor" href="#🚧-in-arbeit" aria-label="Permalink to &quot;🚧 In Arbeit&quot;">​</a></h2><ul><li>[x] Einführung &amp; erste Schritte</li><li>[x] Skill-Übersicht</li><li>[ ] Detaillierte Skill-Beschreibungen</li><li>[ ] Konfigurations-Guide</li><li>[ ] Tipps aus der Praxis</li><li>[ ] Multi-Platform Setup (Telegram, Discord)</li><li>[ ] Eigenen Skill schreiben</li></ul><hr><p><em>Hinweis: Dies ist ein inoffizielles Fan-Projekt.</em></p>',14)])])}const p=r(a,[["render",s]]);export{u as __pageData,p as default};
